/* LegalType Web Keyboard — SVG keyboard renderer + input handler.
 *
 * Renders the LegalType keyboard by inlining assets/svg/keyboard.svg and
 * laying transparent hit-target rectangles on top of every keycap. The
 * rectangles come from assets/js/svg-keycaps.js (auto-generated by
 * scripts/extract_keycaps.py) and carry the KeyboardEvent.code for the
 * key they cover, so clicks dispatch through the same code path that
 * physical keypresses do.
 *
 * The visible legends — letters, AltGr symbols, F-row marks, etc. — are
 * the vector paths that ship inside the SVG itself. We never overwrite
 * them; the on-screen text the user sees is always the SVG's own
 * vectorized typography. Modifier highlight (Shift / AltGr / CapsLock)
 * is reflected as a colored stroke on the matching hit-target.
 */
(function (global) {
  "use strict";

  const SVG_NS = "http://www.w3.org/2000/svg";
  const SVG_URL = "assets/svg/keyboard.svg";

  class Keyboard {
    constructor({ container, target, layout, keycaps }) {
      this.container = container;
      this.target = target;
      this.layout = layout;
      this.keycaps = keycaps; // [{ code, x, y, w, h, row }, ...]

      this.state = {
        shift: false,
        altgr: false,
        capsLock: false,
      };

      // code -> hit-rect element, so we can highlight physical keypresses
      // and show modifier state.
      this.hitRects = new Map();
      this.svgRoot = null;

      this._render();
      this._bindPhysicalKeys();
    }

    /** Replace the layout (currently a no-op since the SVG only ships one)
     * but kept so the toolbar's layout picker can stay wired up. */
    setLayout(layout) {
      this.layout = layout;
    }

    /* ---- rendering ------------------------------------------------ */

    async _render() {
      let svgText;
      try {
        const res = await fetch(SVG_URL);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        svgText = await res.text();
      } catch (err) {
        console.error("Failed to load keyboard SVG:", err);
        this.container.textContent =
          "Couldn't load the keyboard graphic. Try refreshing.";
        return;
      }

      // Strip the XML prolog so we can inject the <svg> directly.
      svgText = svgText.replace(/<\?xml[^>]*\?>\s*/, "");
      this.container.innerHTML = svgText;

      const svg = this.container.querySelector("svg");
      if (!svg) return;
      this.svgRoot = svg;

      // Make the SVG scale to its container.
      svg.setAttribute("preserveAspectRatio", "xMidYMid meet");
      svg.style.width = "100%";
      svg.style.height = "auto";
      svg.style.display = "block";

      this._addHitTargets(svg);
      this._bindClicks(svg);
    }

    /** Add transparent <rect>s above every keycap so we can intercept
     * clicks and show modifier-state highlights. The rects are added as
     * a single group at the top of the SVG so they stack above the
     * keycap shadows but the original legends still shine through. */
    _addHitTargets(svg) {
      const layer = document.createElementNS(SVG_NS, "g");
      layer.setAttribute("id", "kb-hit-layer");
      // Ensure the highlight strokes don't get clipped by aliased edges.
      layer.setAttribute("style", "fill: transparent; stroke: transparent;");

      for (const cap of this.keycaps) {
        const rect = document.createElementNS(SVG_NS, "rect");
        rect.setAttribute("x", cap.x);
        rect.setAttribute("y", cap.y);
        rect.setAttribute("width", cap.w);
        rect.setAttribute("height", cap.h);
        rect.setAttribute("rx", "4.23");
        rect.setAttribute("ry", "4.23");
        rect.setAttribute("class", "kb-hit");
        rect.dataset.code = cap.code;
        layer.appendChild(rect);
        this.hitRects.set(cap.code, rect);
      }

      svg.appendChild(layer);
    }

    /* ---- click handling ------------------------------------------- */

    _bindClicks(svg) {
      svg.addEventListener("click", (e) => {
        const t = e.target;
        if (!(t instanceof Element)) return;
        const code = t.dataset && t.dataset.code;
        if (!code) return;
        const spec = this._specFor(code);
        if (spec) this._handleClick(spec);
      });
    }

    _handleClick(spec) {
      switch (spec.code) {
        case "ShiftLeft":
        case "ShiftRight":
          this.state.shift = !this.state.shift;
          this._refreshModHighlights();
          return;
        case "AltRight":
          this.state.altgr = !this.state.altgr;
          this._refreshModHighlights();
          return;
        case "CapsLock":
          this.state.capsLock = !this.state.capsLock;
          this._refreshModHighlights();
          return;
        case "Backspace":
          this._deleteBack();
          break;
        case "Tab":
          this._insert("\t");
          break;
        case "Enter":
        case "NumpadEnter":
          this._insert("\n");
          break;
        case "Space":
          this._insert(" ");
          break;
        default: {
          if (spec.mod) return; // Other modifiers / nav keys are no-ops.
          const out = this._resolveOutput(spec);
          if (out && out.length >= 1) this._insert(out);
        }
      }

      // Click-style sticky modifiers: a single tap of the on-screen
      // Shift / AltGr drops back to the base layer after one keystroke.
      if (this.state.shift) {
        this.state.shift = false;
        this._refreshModHighlights();
      }
      if (this.state.altgr) {
        this.state.altgr = false;
        this._refreshModHighlights();
      }
    }

    /** Pick the character a given key produces given current state. */
    _resolveOutput(spec) {
      if (this.state.altgr && spec.altgr) return spec.altgr;
      const isUpper = this.state.shift !== this.state.capsLock;
      const isLetter = /^[a-zA-Z]$/.test(spec.base);
      if (isLetter) return isUpper ? spec.shift : spec.base;
      return this.state.shift && spec.shift ? spec.shift : spec.base;
    }

    /** Look up the layout spec for a KeyboardEvent.code — falls back to
     * a synthetic spec so unknown keys (Numpad / nav cluster / F-row)
     * still print a sensible character when clicked. The returned spec
     * always carries `code`, since _handleClick switches on it. */
    _specFor(code) {
      if (this.layout && this.layout.specs && this.layout.specs[code]) {
        return Object.assign({ code }, this.layout.specs[code]);
      }
      const fallback = FALLBACKS[code];
      if (fallback) return Object.assign({ code }, fallback);
      return { code, base: null, shift: null, altgr: null, mod: true };
    }

    _refreshModHighlights() {
      this._reflectMod("ShiftLeft", this.state.shift);
      this._reflectMod("ShiftRight", this.state.shift);
      this._reflectMod("AltRight", this.state.altgr);
      this._reflectMod("CapsLock", this.state.capsLock);
    }

    _reflectMod(code, active) {
      const r = this.hitRects.get(code);
      if (!r) return;
      r.classList.toggle("is-toggled", !!active);
    }

    /* ---- physical keyboard ---------------------------------------- */

    _bindPhysicalKeys() {
      const onDown = (e) => {
        const r = this.hitRects.get(e.code);
        if (r) r.classList.add("is-pressed");
        if (e.code === "ShiftLeft" || e.code === "ShiftRight") {
          this.state.shift = true;
          this._refreshModHighlights();
        } else if (e.code === "AltRight") {
          this.state.altgr = true;
          this._refreshModHighlights();
        } else if (e.code === "CapsLock") {
          this.state.capsLock = !this.state.capsLock;
          this._refreshModHighlights();
        }
      };
      const onUp = (e) => {
        const r = this.hitRects.get(e.code);
        if (r) r.classList.remove("is-pressed");
        if (e.code === "ShiftLeft" || e.code === "ShiftRight") {
          this.state.shift = false;
          this._refreshModHighlights();
        } else if (e.code === "AltRight") {
          this.state.altgr = false;
          this._refreshModHighlights();
        }
      };
      window.addEventListener("keydown", onDown);
      window.addEventListener("keyup", onUp);
    }

    /* ---- text manipulation ---------------------------------------- */

    _insert(text) {
      const ta = this.target;
      ta.focus();
      const start = ta.selectionStart ?? ta.value.length;
      const end = ta.selectionEnd ?? ta.value.length;
      ta.value = ta.value.slice(0, start) + text + ta.value.slice(end);
      const caret = start + text.length;
      ta.selectionStart = ta.selectionEnd = caret;
    }

    _deleteBack() {
      const ta = this.target;
      ta.focus();
      const start = ta.selectionStart ?? 0;
      const end = ta.selectionEnd ?? 0;
      if (start !== end) {
        ta.value = ta.value.slice(0, start) + ta.value.slice(end);
        ta.selectionStart = ta.selectionEnd = start;
      } else if (start > 0) {
        ta.value = ta.value.slice(0, start - 1) + ta.value.slice(start);
        ta.selectionStart = ta.selectionEnd = start - 1;
      }
    }
  }

  /** Synthetic specs for keys that are present on the SVG keyboard but
   * not in the legal-en layout (numpad / nav cluster / F-row). The
   * numpad echoes its label literally; the nav cluster and F-row are
   * inert click targets so users can still see which keys are which. */
  const FALLBACKS = {
    Numpad0: { base: "0", shift: "0", altgr: null },
    Numpad1: { base: "1", shift: "1", altgr: null },
    Numpad2: { base: "2", shift: "2", altgr: null },
    Numpad3: { base: "3", shift: "3", altgr: null },
    Numpad4: { base: "4", shift: "4", altgr: null },
    Numpad5: { base: "5", shift: "5", altgr: null },
    Numpad6: { base: "6", shift: "6", altgr: null },
    Numpad7: { base: "7", shift: "7", altgr: null },
    Numpad8: { base: "8", shift: "8", altgr: null },
    Numpad9: { base: "9", shift: "9", altgr: null },
    NumpadDivide: { base: "/", shift: "/", altgr: null },
    NumpadMultiply: { base: "*", shift: "*", altgr: null },
    NumpadSubtract: { base: "-", shift: "-", altgr: null },
    NumpadAdd: { base: "+", shift: "+", altgr: null },
    NumpadDecimal: { base: ".", shift: ".", altgr: null },
    NumpadEnter: { base: "\n", shift: "\n", altgr: null },
    // Nav and F-row are visual-only; clicks are no-ops.
  };

  global.LegalTypeKeyboard = Keyboard;
})(window);
